from fastcore.all import Path, Generator, patch, Optional, Union, Iterable, merge, ifnone, parallel
from fastlite import Database
from apswutils.db import Table
from apswutils.utils import cursor_row2dict
import numpy as np

_dtype_suffixes = {np.int8: 'i8', np.float16: 'f16', np.float64: 'f64', np.float32: 'f32'}
def _dtype_suffix(dtype=np.float16): return _dtype_suffixes.get(dtype, 'f32')

# %% ../nbs/01_core.ipynb #ddeccc26
@patch
def query(self: Database, sql: str, params: Optional[Union[Iterable, dict]] = None) -> Generator[dict, None, None]:
    '''Execute a query and return results as a list of AttrDict'''
    p = params if isinstance(params, dict) else tuple(params or tuple())
    cursor = self.execute(sql, p)
    cursor.row_trace = cursor_row2dict
    yield from cursor

