@patch
def search(self: Database,  # database connection
           q:str,  # query string
           emb:bytes,  # embedding vector
           columns:list=None,  # columns to return
           where:str=None,  # additional where clause
           where_args:dict=None,  # args for where clause
           limit:int|None=50,  # limit on number of results
           offset:int|None=None,  # offset for results (ignored when rrf=True)
           table_name='store',  # table name
           emb_col='embedding',  # embedding column name
           emb_metric:str='cosine',  # embedding distance metric (cosine,sqeuclidean,inner,divergence)
           rrf=True,  # rerank results with reciprocal rank fusion
           rrf_k:int=60,  # RRF k parameter
           dtype=np.float16,  # embedding dtype
           id_key:str='rowid',  # key to join RRF results on
           quote:bool=False,  # quote FTS query to disable special chars
           ):
    'Search the litesearch store with fts and vector search combined.'
    if not q.strip(): return None
    tbl = self.t[table_name]
    cols = list(columns or [])
    if rrf and id_key not in cols: cols = [id_key] + cols
    fts_q= self.quote_fts(q) if quote else q
    lim, off = (limit + offset) if rrf and offset else limit, offset if not rrf else None
    sql = tbl.search_sql(order_by='rank', columns=cols, limit=lim, where=where, include_rank=True, offset=off)
    fts = self.q(sql, merge(dict(query=fts_q), where_args or {}))
    vec = tbl.vec_search(emb, columns=cols, where=where, where_args=where_args, emb_col=emb_col, emb_metric=emb_metric,
                         dtype=dtype, limit=lim, offset=off)
    if rrf: return rrf_merge(fts, vec, k=rrf_k, limit=lim, id_key=id_key)[ifnone(off, 0):]
    return dict(fts=fts, vec=vec)

# %% ../nbs/01_core.ipynb #76894841
def format_for_context(results: list,        # list of dicts from db.search(), ranked by RRF score
                       max_tokens: int=4096, # approximate token budget (1 token ≈ 4 chars)
                       template: str=None,   # per-result format string; may use {score}, {source}, {content}
                       ) -> str:
    "Format search results into a context string within a token budget. Truncates to fit."
    tmpl = template or '[{score:.3f}] {source}\n{content}'
    out, budget = [], max_tokens * 4  # convert tokens → char budget
    for r in results:
        s = tmpl.format(score=r.get('_rrf_score', 0.0), source=r.get('metadata', ''), content=r.get('content', ''))
        if len(s) > budget: s = s[:budget]
        out.append(s)
        budget -= len(s)
        if budget <= 0: break
    return '\n\n'.join(out)

