from fastcore.imports import llmtool
import json

def get_search_tool(db,              # database connection
                    enc,             # encoder with encode_query(texts) -> list[np.ndarray]
                    store:str='store', # table name to search
                    top_k:int=10,    # default number of results
                    dtype=np.float16 # embedding dtype matching the stored embeddings
                    ):
    "Return an @llmtool-decorated search function bound to this db and encoder. Pass to claudette or any tool-use framework."
    def search_documents(query: str, n_results: int = top_k) -> str:
        """Search indexed documents for the given query. Returns top results as JSON with content, score, source and rank."""
        emb = enc.encode_query([query])[0].ravel().tobytes()
        results = db.search(query, emb, table_name=store, limit=n_results, dtype=dtype)
        return json.dumps([{'content': r.get('content', ''), 'score': r.get('_rrf_score', 0.0),
                            'source': r.get('metadata', ''), 'rank': i}
                           for i, r in enumerate(results or [])])
    return llmtool(search_documents)

