from usearch.index import Index as USearchIndex

class SemanticCache:
    "In-memory semantic cache backed by a usearch HNSW index. Supports matryoshka truncation for fast lookups."
    def __init__(self,
                 ndim: int,              # full embedding dimension
                 threshold: float=0.05, # cosine distance threshold for a cache hit
                 metric: str='cos',     # distance metric for the usearch Index
                 dtype=np.float32,      # numpy dtype used when trimming embeddings
                 truncate_to: int=None, # matryoshka: use only the first N dims for cache lookup
                 ):
        self.dim = truncate_to or ndim
        self.index = USearchIndex(ndim=self.dim, metric=metric)
        self._cache = {}
        self.threshold = threshold
        self.truncate_to = truncate_to
        self._metric = metric

    def _trim(self, emb: np.ndarray) -> np.ndarray:
        v = emb[:self.truncate_to] if self.truncate_to else emb
        return np.asarray(v, dtype=np.float32)

    def lookup(self, emb: np.ndarray):
        "Return cached result if nearest stored embedding is within threshold distance, else None."
        if not len(self.index): return None
        matches = self.index.search(self._trim(emb), 1)
        if len(matches) and matches[0].distance < self.threshold:
            return self._cache[int(matches[0].key)]
        return None

    def store(self, emb: np.ndarray, result):
        "Add result to the cache keyed by its embedding."
        k = len(self._cache)
        self.index.add(k, self._trim(emb))
        self._cache[k] = result

    def clear(self):
        "Evict all cached entries."
        self.index = USearchIndex(ndim=self.dim, metric=self._metric)
        self._cache = {}

    def __len__(self): return len(self._cache)
    def __repr__(self): return f'SemanticCache(entries={len(self)}, dim={self.dim}, threshold={self.threshold})'

# %% ../nbs/01_core.ipynb #1475920e
def search_batch(db,                  # database connection
                 queries_embs: list,  # list of (query_str, emb_bytes) pairs
                 cache=None,          # optional SemanticCache to check/populate
                 **kwargs             # passed to db.search()
                 ) -> list:
    "Run multiple searches in parallel. Returns list of result lists in the same order as queries_embs."
    dtype = kwargs.get('dtype', np.float16)
    def _search(qe):
        q, emb = qe
        if cache is not None:
            emb_arr = np.frombuffer(emb, dtype=dtype)
            hit = cache.lookup(emb_arr)
            if hit is not None: return hit
        result = db.search(q, emb, **kwargs)
        if cache is not None and result:
            cache.store(np.frombuffer(emb, dtype=dtype), result)
        return result
    return list(parallel(_search, queries_embs, threadpool=True))
